```cpp
#include <iostream>
#include <unistd.h>
#include <fcntl.h>
#include <sys/types.h>
#include <sys/wait.h>

int main() {
    int fd[2];  // File descriptor for pipe
    pid_t pid;

    // Create a pipe
    if (pipe(fd) == -1) {
        perror("pipe");
        return 1;
    }

    // Fork a new process
    pid = fork();
    if (pid == -1) {
        perror("fork");
        return 1;
    }

    // Child process
    if (pid == 0) {
        // Close unused half of the pipe
        close(fd[1]);  // Close write end in child

        // Redirect input and output to the pipe
        dup2(fd[0], STDIN_FILENO);  // Redirect stdin to read end of pipe
        dup2(fd[0], STDOUT_FILENO); // Redirect stdout to read end of pipe

        // Close the pipe (not necessary, but good practice)
        close(fd[0]);

        // Execute some command or program
        execlp("/bin/cat", "cat", NULL);  // Example command
        perror("execlp");
        exit(1);
    } else {
        // Parent process
        close(fd[0]);  // Close unused half of the pipe

        // Write to the write end of the pipe
        write(fd[1], "Hello from parent process", 29);

        // Close write end
        close(fd[1]);

        // Wait for child to finish
        wait(NULL);
        std::cout << "Parent process received: ";
        std::cin.get();
    }

    return 0;
}
```

This script emphasizes the creation of a pipe, forking a new process, and redirecting file descriptors to connect the parent and child processes.

